import { createStore } from "vuex";

export default createStore({
    state: {
        cart: [],
        cartIsOpen: true
    },
    mutations: {
        SET_CART_MENU(state, data) {
            state.cartIsOpen = data;
        },
        SET_CART(state, data) {
            state.cart = data;
        }
    },
    actions: {
        openCart({ commit }) {
            commit("SET_CART_MENU", true);
        },
        closeCart({ commit }) {
            commit("SET_CART_MENU", false);
        },
        getCart({ commit }) {
            fetch("https://" + location.hostname + ":4001/cart")
                .then(r => {
                    return r.json();
                })
                .then(data => {
                    console.log(data)
                    commit("SET_CART", data);
                });
        },
        addToCart({ commit }, data) {
            fetch("https://" + location.hostname + ":4001/cart/add", {
                method: 'POST',
                credentials: "include",
                mode: 'cors',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(data)
            })
                .then(r => {
                    return r.json();
                })
                .then(data => {
                    console.log(data)
                    commit("SET_CART", data);
                });
        }
    },
    getters: {
        cartAmount: state => state.cart.length,
        cartIsOpen: state => state.cartIsOpen
    },
    modules: {}
});
