            </div>
            <div class="modal-footer">
                <h3>Mapp Intelligence demo store</h3>
            </div>
        </div>
    </div>
</template>

<script lang="ts">
import { defineComponent } from "vue";
import { mapGetters, mapActions } from "vuex";
export default defineComponent({
    name: "CartMenu",
    data() {
        return {
        };
    },
    computed: {
        ...mapGetters([
